package com.example.auth.service;

import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Component;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.List;

@Component
public class BackupCodeGenerator {
    private static final String ALPHABET = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
    private static final int SEGMENT_LENGTH = 4;
    private static final int SEGMENTS = 2;
    private static final int DEFAULT_COUNT = 10;

    private final SecureRandom secureRandom = new SecureRandom();
    private final PasswordEncoder passwordEncoder;

    public BackupCodeGenerator(PasswordEncoder passwordEncoder) {
        this.passwordEncoder = passwordEncoder;
    }

    public List<String> generatePlainCodes() {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < DEFAULT_COUNT; i++) {
            codes.add(generateCode());
        }
        return codes;
    }

    public String hash(String code) {
        return passwordEncoder.encode(normalize(code));
    }

    public boolean matches(String rawCode, String hash) {
        return passwordEncoder.matches(normalize(rawCode), hash);
    }

    public String normalize(String code) {
        return code == null ? "" : code.replace("-", "").replace(" ", "").trim().toUpperCase();
    }

    private String generateCode() {
        StringBuilder sb = new StringBuilder();
        for (int segment = 0; segment < SEGMENTS; segment++) {
            if (segment > 0) {
                sb.append("-");
            }
            for (int i = 0; i < SEGMENT_LENGTH; i++) {
                sb.append(ALPHABET.charAt(secureRandom.nextInt(ALPHABET.length())));
            }
        }
        return sb.toString();
    }
}

package com.example.auth.service;

import com.example.auth.model.BackupCode;
import com.example.auth.model.User;
import com.example.auth.repository.BackupCodeRepository;
import com.example.auth.repository.UserRepository;
import jakarta.transaction.Transactional;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {
    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final BackupCodeGenerator backupCodeGenerator;

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             UserRepository userRepository,
                             BackupCodeGenerator backupCodeGenerator) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.backupCodeGenerator = backupCodeGenerator;
    }

    @Transactional
    public List<String> regenerateForUser(User user) {
        backupCodeRepository.deleteByUser(user);
        List<String> plainCodes = backupCodeGenerator.generatePlainCodes();
        List<BackupCode> entities = new ArrayList<>();
        for (String plain : plainCodes) {
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(backupCodeGenerator.hash(plain));
            code.setConsumed(false);
            entities.add(code);
        }
        backupCodeRepository.saveAll(entities);
        return plainCodes;
    }

    @Transactional
    public boolean consumeBackupCode(User user, String rawCode) {
        List<BackupCode> activeCodes = backupCodeRepository.findByUserAndConsumedFalse(user);
        for (BackupCode backupCode : activeCodes) {
            if (backupCodeGenerator.matches(rawCode, backupCode.getCodeHash())) {
                backupCode.setConsumed(true);
                backupCode.setConsumedAt(Instant.now());
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        return false;
    }

    public long remainingCodes(User user) {
        return backupCodeRepository.findByUserAndConsumedFalse(user).size();
    }

    @Transactional
    public List<String> enableMfaAndGenerateCodes(String username, String totpSecret) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setMfaEnabled(true);
        user.setTotpSecret(totpSecret);
        userRepository.save(user);
        return regenerateForUser(user);
    }
}

