package com.example.auth.service;

import com.example.auth.dto.AuthResponse;
import com.example.auth.model.MfaMethod;
import com.example.auth.model.User;
import com.example.auth.repository.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
public class AuthenticationService {
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;

    public AuthenticationService(UserRepository userRepository,
                                 PasswordEncoder passwordEncoder,
                                 TotpService totpService,
                                 BackupCodeService backupCodeService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
    }

    public AuthResponse authenticate(String username, String password, String totpCode, String backupCode) {
        User user = userRepository.findByUsername(username)
                .orElse(null);

        if (user == null || !passwordEncoder.matches(password, user.getPasswordHash())) {
            return new AuthResponse(false, "Invalid username or password", null);
        }

        if (!user.isMfaEnabled()) {
            return new AuthResponse(true, "Authenticated without MFA", null);
        }

        if (totpCode != null && !totpCode.isBlank() && totpService.verifyCode(user.getTotpSecret(), totpCode)) {
            return new AuthResponse(true, "Authenticated with TOTP", MfaMethod.TOTP.name());
        }

        if (backupCode != null && !backupCode.isBlank() && backupCodeService.consumeBackupCode(user, backupCode)) {
            return new AuthResponse(true, "Authenticated with backup code", MfaMethod.BACKUP_CODE.name());
        }

        return new AuthResponse(false, "MFA required: provide valid TOTP or backup code", null);
    }
}

